nd Cross","pattern_zh":"大十字","pattern_zht":"大十字","objects":[{"object_type":"planet","code_name":"0","planet_english":"Sun","planet_chinese":"太阳","planet_chinese_traditional":"太阳","planet_font":"Su"},{"object_type":"planet","code_name":"5","planet_english":"Jupiter","planet_chinese":"木星","planet_chinese_traditional":"木星","planet_font":"Ju"},{"object_type":"angle","code_name":"MC","planet_english":"Midheaven","planet_chinese":"天顶","planet_chinese_traditional":"天頂","planet_font":"Mc"},{"object_type":"angle","code_name":"IC","planet_english":"ImumCoeli","planet_chinese":"天底","planet_chinese_traditional":"天底","planet_font":"Ic"}]}]},"chart_description":{"summary":[{"target":"運勢基調：月亮落入第12宮","description":"月返月亮落十二宮，本月核心消耗集中在潛意識、靈性與隱憂層面。你易因潛藏的情緒、未解決的心理問題耗費心神，或在獨處時陷入過度的自我反思、精神內耗，甚至因幫助他人、承擔無形的責任而透支精力。需學會與自己和解，適度放空，避免被潛意識的情緒漩渦過度消耗。"}],"houses":[{"target":"返照第1宮落入獅子座","description":"月返第一宮被激活，這幾周，你的自我認知與外在狀態迎來明顯變化。你會更關注自身感受、形象與行動力，容易做出即興的決定，也可能在健康、個人形象上有新的調整。這段時間自我表達欲強烈，是重塑自我狀態的關鍵期。"},{"target":"返照第4宮落入天蠍座","description":"月返第四宮被激活，這幾周，你的家庭與內心安全感層面有明顯變動。可能涉及家居布置調整、與家人深度溝通，或收到關於房產、家族事務的消息。內心對「家」的歸屬感需求強烈，容易在家庭事務上投入更多精力，是梳理家庭關係的窗口期。"},{"target":"返照第5宮落入射手座","description":"月返第五宮被激活，這幾周，你的創造力、娛樂與情感表達迎來高峰。容易有浪漫邂逅、參與娛樂活動，或在創作、親子互動上有新的體驗。個人魅力提升，願意主動展現自我，是享受生活、釋放創造力的短期機遇期。"},{"target":"返照第12宮落入巨蟹座","description":"月返第十二宮被激活，這幾周，你的潛意識、靈性與隱憂層面迎來梳理期。容易陷入深度自省、接觸靈性相關事物，或需處理隱藏的情緒、未解決的過往問題。適合獨處休整，是與自我和解、釋放心理負擔的短期調整期。"}],"planets":{"sign":[{"target":"返照月亮落入獅子座","description":"月返月亮落入獅子座，本月你的情緒張揚且渴望被認可，內心期待被看見、被讚美，有強烈的表現欲。容易因得不到關注而感到失落，也會因好面子做出情緒化的選擇。需正視自己的情緒需求，把這份渴望轉化為自我價值的提升，而非單純尋求外界的肯定。"}],"house":[{"target":"返照月亮落入第12宮","description":"月返月亮落第十二宮，本月你的情緒偏向內斂、潛意識與隱秘感受。容易莫名疲憊、多思、敏感，情緒不易對外表達，更需要獨處、靜養、療癒。適合放下外界期待，清理潛意識負擔，在安靜與自我接納中修復情緒、積蓄內在力量。"},{"target":"返照水星落入第5宮","description":"月返水星落第五宮，本月思維偏向創意、娛樂、情感、表達與創作。表達更輕鬆有趣，適合戀愛溝通、創意策劃、學習興趣、表達才華。思路富有想像力，利於創作、表演、親子交流，用輕鬆的思維收穫快樂與靈感。"}]},"angles":[{"target":"返照上升落入獅子座","description":"月返上升獅子座，本月你的對外態度自信且愛表現，行事大方、渴望被認可，不願默默無聞。外在表現熱情張揚，容易給人有魅力、有氣場的印象，但需留意過度自我導致的傲慢，在展現中保持謙遜。"}],"aspects":[{"target":"返照月亮 對分相 太陽","description":"月返月亮沖太陽，本月你的情緒與自我意志形成對立，易陷入自我矛盾，外在表現與內心感受脫節。行事易情緒化或刻意壓抑自我，需在滿足自我需求與關照情緒間找到平衡，避免身心背離。"}]},"chart_svg":"<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n        <svg width=\"720\" height=\"720\"\n             shape-rendering=\"geometricPrecision\"\n             viewBox=\"0 0 720 720\"\n             xmlns=\"http:\/\/www.w3.org\/2000\/svg\"\n             class=\"astrology-chart\"\n             data-chart-type=\"single\"\n             data-chart-engine=\"yuanfenju-modern-svg\"\n             data-chart-version=\"1.0\"\n             data-api-version=\"1.0\"\n             data-layout-version=\"1.3\"\n             data-style-contract=\"css-variables-v1\">\n\n            <defs>\n                <style type=\"text\/css\">\n                    <![CDATA[\n                    :root {\n                        --chart-text-color: currentColor;\n                        --chart-font-family: Arial, sans-serif;\n\n                        --chart-ring-stroke: currentColor;\n\n                        --chart-aspect-hard-color: #d00;\n                        --chart-aspect-soft-color: #0a0;\n                        --chart-aspect-minor-color: #0b0;\n                        --chart-aspect-square-color: #00a;\n                        --chart-aspect-quincunx-color: #fa0;\n                        --chart-retrograde-color: red;\n                        --chart-connector-stroke: currentColor;\n\n                        \/* 新增显式声明（文档要求） *\/\n                        --chart-house-axis-width: 1.6;\n                        --chart-planet-hit-area-radius: 18;\n                    }\n\n                    \/* 其余样式保持不变 *\/\n                    .ring, .house-cusp-line, .aspect, .planet-connector, .center-cross path {\n                        fill: none;\n                        stroke: var(--chart-ring-stroke);\n                        vector-effect: non-scaling-stroke;\n                        stroke-linecap: butt;\n                    }\n\n                    .ring-outer { stroke-width: var(--chart-ring-outer-width, 1.8); }\n                    .ring-zodiac { stroke-width: var(--chart-ring-zodiac-width, 1.3); fill: none; }\n                    .ring-house { stroke-width: var(--chart-ring-house-width, 1); }\n                    .ring-planet-logic { stroke-width: var(--chart-ring-planet-logic-width, 0.8); }\n                    .ring-aspect { stroke-width: var(--chart-ring-aspect-width, 1); opacity: var(--chart-aspect-ring-opacity, 0.25); }\n                    .ring-inner-min { stroke-width: var(--chart-ring-inner-min-width, 0.5); opacity: var(--chart-ring-inner-min-opacity, 0.6); }\n\n                    .house-cusp-line { stroke-width: var(--chart-house-cusp-width, 1); opacity: var(--chart-house-cusp-opacity, 0.7); }\n                    .house-cusp-line.axis { stroke-width: var(--chart-house-axis-width, 1.6); opacity: var(--chart-house-axis-opacity, 0.9); }\n\n                    .aspect { opacity: var(--chart-aspect-opacity, 0.5); }\n\n                    .aspect-conjunction, .aspect-opposition {\n                        stroke: var(--chart-aspect-hard-color);\n                        stroke-width: var(--chart-aspect-hard-width, 2.5);\n                        stroke-dasharray: var(--chart-aspect-hard-dash, 5,3);\n                    }\n                    .aspect-semisextile, .aspect-quincunx {\n                        stroke: var(--chart-aspect-minor-color);\n                        stroke-width: var(--chart-aspect-minor-width, 1.2);\n                        stroke-dasharray: var(--chart-aspect-minor-dash, 1,5);\n                    }\n                    .aspect-sextile, .aspect-trine {\n                        stroke: var(--chart-aspect-soft-color);\n                        stroke-width: var(--chart-aspect-soft-width, 1.5);\n                        stroke-dasharray: var(--chart-aspect-soft-dash, 2,4);\n                    }\n                    .aspect-square {\n                        stroke: var(--chart-aspect-square-color);\n                        stroke-width: var(--chart-aspect-square-width, 2);\n                        stroke-dasharray: var(--chart-aspect-square-dash, 3,3);\n                    }\n\n                    text {\n                        fill: var(--chart-text-color);\n                        font-family: var(--chart-font-family);\n                    }\n\n                    .house-number { font-size: var(--chart-house-number-size, 16px); }\n                    .zodiac-sign { font-size: var(--chart-zodiac-sign-size, 28px); font-weight: bold; }\n                    .planet-symbol { font-size: var(--chart-planet-symbol-size, 20px); }\n                    .planet-position { font-size: var(--chart-planet-position-size, 12px); }\n                    .planet-sign-symbol { font-size: var(--chart-planet-sign-symbol-size, 22px); font-weight: bold; }\n                    .retrograde-indicator { font-size: var(--chart-retrograde-size, 12px); fill: var(--chart-retrograde-color); }\n\n                    .planet-connector {\n                        stroke: var(--chart-connector-stroke);\n                        stroke-width: var(--chart-connector-width, 1);\n                        opacity: var(--chart-connector-opacity, 0.3);\n                    }\n\n                    .planet-hit-area { fill: none; opacity: 0; cursor: pointer; }\n                    ]]>\n                <\/style>\n            <\/defs>\n\n            <g class=\"chart\"\n               data-layout-token=\"chart-root\"\n               data-outer-radius=\"295\"\n               data-zodiac-radius=\"260\"\n               data-house-radius=\"220\"\n               data-planet-logic-radius=\"180\"\n               data-planet-draw-base-radius=\"170\"\n               data-aspect-radius=\"135\"\n               data-inner-min-radius=\"80\"\n               data-planet-stack-spacing=\"16\"\n               data-planet-label-horizontal-offset=\"20\"\n               data-planet-stack-angle=\"5\"\n               data-planet-label-line-spacing=\"20\"\n               data-planet-hit-area-radius=\"18\">\n                <!-- 负责绘制所有基础圆环与定位辅助线，不包含占星数据 -->\n                <g class=\"chart-layer\" data-layer=\"background\">\n                    <!-- 最外框边界（星盘整体外轮廓） -->\n                    <circle class=\"ring ring-outer\" cx=\"360\" cy=\"360\" r=\"295\" \/>\n                    <!-- 黄道带主环（12星座所在区域） -->\n                    <circle class=\"ring ring-zodiac\" cx=\"360\" cy=\"360\" r=\"260\" \/>\n                    <!-- 宫位结构环（12宫划分区域） -->\n                    <circle class=\"ring ring-house\" cx=\"360\" cy=\"360\" r=\"220\" \/>\n                    <!-- 行星逻辑排布环（用于行星防重叠计算，不一定可见） -->\n                    <circle class=\"ring ring-planet-logic\" cx=\"360\" cy=\"360\" r=\"180\" \/>\n                    <!-- 相位绘制边界环（相位线绘制范围） -->\n                    <circle class=\"ring ring-aspect\" cx=\"360\" cy=\"360\" r=\"135\" \/>\n                    <!-- 内部最小安全边界（避免相位线贴近中心） -->\n                    <circle class=\"ring ring-inner-min\" cx=\"360\" cy=\"360\" r=\"80\" \/>\n                    <!-- 中心十字定位标记（仅视觉辅助） -->\n                    <g class=\"center-cross\">\n                        <path d=\"M 360,350 V 370 M 350,360 H 370\" \/>\n                    <\/g>\n                <\/g>\n\n                <!-- ====================== 星座层 ====================== -->\n                <!-- 绘制十二星座符号、分区背景、星座刻度 -->\n                <g class=\"chart-layer\" data-layer=\"zodiac\">\n                    <text class=\"zodiac-sign\" x=\"520.41957834696\" y=\"136.6380540849\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"0\" data-sign-name=\"aries\" data-object-id=\"zodiac-aries\">♈<\/text><text class=\"zodiac-sign\" x=\"387.24645715531\" y=\"86.353091425311\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"1\" data-sign-name=\"taurus\" data-object-id=\"zodiac-taurus\">♉<\/text><text class=\"zodiac-sign\" x=\"246.77266977228\" y=\"109.39159692959\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"2\" data-sign-name=\"gemini\" data-object-id=\"zodiac-gemini\">♊<\/text><text class=\"zodiac-sign\" x=\"136.6380540849\" y=\"199.58042165304\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"3\" data-sign-name=\"cancer\" data-object-id=\"zodiac-cancer\">♋<\/text><text class=\"zodiac-sign\" x=\"86.353091425311\" y=\"332.75354284469\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"4\" data-sign-name=\"leo\" data-object-id=\"zodiac-leo\">♌<\/text><text class=\"zodiac-sign\" x=\"109.39159692959\" y=\"473.22733022772\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"5\" data-sign-name=\"virgo\" data-object-id=\"zodiac-virgo\">♍<\/text><text class=\"zodiac-sign\" x=\"199.58042165304\" y=\"583.3619459151\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"6\" data-sign-name=\"libra\" data-object-id=\"zodiac-libra\">♎<\/text><text class=\"zodiac-sign\" x=\"332.75354284469\" y=\"633.64690857469\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"7\" data-sign-name=\"scorpio\" data-object-id=\"zodiac-scorpio\">♏<\/text><text class=\"zodiac-sign\" x=\"473.22733022772\" y=\"610.60840307041\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"8\" data-sign-name=\"sagittarius\" data-object-id=\"zodiac-sagittarius\">♐<\/text><text class=\"zodiac-sign\" x=\"583.3619459151\" y=\"520.41957834696\" text-anchor=\"middle\" dominant-baseline=\"central\" data-type=\"zodiac-sign\" data-sign-id=\"9\" data-sign-name=\"capricorn\" data-object-id=\"zodiac-capricorn\">♑<\/text><text class=\"zodiac-sign\" x=\"633.64690857469\" y=\"387.24645715531\" text-anchor=\"middle\" dominant-baseline=\"centra